import { useEffect, useState, useRef, type FormEvent } from "react";
import { useAuth } from "../../context/AuthContext";
import { useTheme } from "../../context/ThemeContext";
import { getMe, updateProfile, changePassword, uploadUserPhoto } from "../../api/authApi";
import AlertMessage from "../../components/AlertMessage";
import type { User } from "../../types/auth";

export default function Settings() {
  const { auth } = useAuth();

  const [user, setUser]             = useState<User | null>(null);
  const [profile, setProfile]       = useState({ display_name: "", email: "", phone: "" });
  const [pwForm, setPwForm]         = useState({ current_password: "", new_password: "", confirm_password: "" });
  const [alert, setAlert]           = useState({ type: "", message: "" });
  const [saving, setSaving]         = useState(false);
  const [pwSaving, setPwSaving]     = useState(false);
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  const { theme, saveTheme } = useTheme();
  const [themeForm, setThemeForm] = useState({
    mode: theme.mode as "light" | "dark" | "custom",
    primaryColor: theme.primaryColor,
    accentColor: theme.accentColor,
  });
  const [themeSaving, setThemeSaving] = useState(false);

  async function handleThemeSave() {
    setThemeSaving(true);
    try {
      await saveTheme(themeForm);
      setAlert({ type: "success", message: "Theme saved successfully." });
    } catch (e: any) {
      setAlert({ type: "danger", message: e.message });
    } finally {
      setThemeSaving(false);
    }
  }

  useEffect(() => {
    getMe()
      .then((res) => {
        setUser(res.data);
        setProfile({
          display_name: res.data.display_name || "",
          email: res.data.email || "",
          phone: res.data.phone || "",
        });
      })
      .catch((e: Error) => setAlert({ type: "danger", message: e.message }));
  }, []);

  async function handleProfileSave(e: FormEvent) {
    e.preventDefault();
    setSaving(true);
    try {
      const res = await updateProfile(profile);
      setUser(res.data);
      setAlert({ type: "success", message: "Profile updated successfully." });
    } catch (e: any) {
      setAlert({ type: "danger", message: e.message });
    } finally {
      setSaving(false);
    }
  }

  async function handlePasswordChange(e: FormEvent) {
    e.preventDefault();
    if (pwForm.new_password !== pwForm.confirm_password) {
      setAlert({ type: "danger", message: "New passwords do not match." });
      return;
    }
    setPwSaving(true);
    try {
      await changePassword({
        current_password: pwForm.current_password,
        new_password: pwForm.new_password,
      });
      setAlert({ type: "success", message: "Password changed successfully. Use the new password on next login." });
      setPwForm({ current_password: "", new_password: "", confirm_password: "" });
    } catch (e: any) {
      setAlert({ type: "danger", message: e.message });
    } finally {
      setPwSaving(false);
    }
  }

  function handleFileSelect(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) {
      setAlert({ type: "danger", message: "Image must be under 5 MB." });
      return;
    }
    const reader = new FileReader();
    reader.onload = () => {
      const dataUrl = reader.result as string;
      setPhotoPreview(dataUrl);
    };
    reader.readAsDataURL(file);
  }

  async function handlePhotoUpload() {
    if (!photoPreview) return;
    setSaving(true);
    try {
      const res = await uploadUserPhoto(photoPreview);
      setUser(res.data);
      setPhotoPreview(null);
      setAlert({ type: "success", message: "Photo updated successfully." });
    } catch (e: any) {
      setAlert({ type: "danger", message: e.message });
    } finally {
      setSaving(false);
    }
  }

  const apiBase = process.env.REACT_APP_API_URL || "http://localhost:8088";
  const avatarUrl = user?.photo_path ? `${apiBase}${user.photo_path}` : null;

  return (
    <div className="row justify-content-center">
      <div className="col-md-7">
        <h3 className="fw-bold mb-4">Settings</h3>
        <AlertMessage {...alert} onClose={() => setAlert({ type: "", message: "" })} />

        {/* Account Info (read-only) */}
        <div className="card shadow-sm mb-4">
          <div className="card-header bg-dark text-white fw-semibold">Account Information</div>
          <div className="card-body">
            <div className="row">
              <div className="col-md-3 text-center mb-3">
                {avatarUrl || photoPreview ? (
                  <img
                    src={photoPreview || avatarUrl!}
                    alt="Avatar"
                    className="rounded-circle border"
                    style={{ width: 100, height: 100, objectFit: "cover" }}
                  />
                ) : (
                  <div
                    className="rounded-circle bg-primary d-flex align-items-center justify-content-center mx-auto text-white fw-bold"
                    style={{ width: 100, height: 100, fontSize: 36 }}
                  >
                    {(user?.display_name || user?.username || "?").charAt(0).toUpperCase()}
                  </div>
                )}
                <div className="mt-2">
                  <input type="file" ref={fileRef} className="d-none" accept="image/*" onChange={handleFileSelect} />
                  <button className="btn btn-sm btn-outline-primary" onClick={() => fileRef.current?.click()}>
                    Change Photo
                  </button>
                  {photoPreview && (
                    <button className="btn btn-sm btn-primary ms-2" onClick={handlePhotoUpload} disabled={saving}>
                      Save
                    </button>
                  )}
                </div>
              </div>
              <div className="col-md-9">
                <table className="table table-sm mb-0">
                  <tbody>
                    <tr><th style={{ width: 140 }}>Username</th><td>{user?.username}</td></tr>
                    <tr>
                      <th>Role</th>
                      <td>
                        <span className={`badge bg-${auth?.role === "admin" ? "danger" : auth?.role === "supervisor" ? "warning" : "success"}`}>
                          {auth?.role}
                        </span>
                      </td>
                    </tr>
                    {user?.employee_id && (
                      <tr><th>Employee ID</th><td>#{user.employee_id}</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>

        {/* Appearance */}
        <div className="card shadow-sm mb-4">
          <div className="card-header fw-semibold" style={{ background: "var(--bs-primary)", color: "white" }}>Appearance</div>
          <div className="card-body">
            <div className="d-flex gap-2 mb-3">
              {(["light", "dark", "custom"] as const).map((m) => (
                <button
                  key={m}
                  className={`btn ${themeForm.mode === m ? "btn-primary" : "btn-outline-secondary"} flex-fill`}
                  onClick={() => setThemeForm((f) => ({ ...f, mode: m }))}
                  type="button"
                >
                  {m === "light" ? "☀️ Light" : m === "dark" ? "🌙 Dark" : "🎨 Custom"}
                </button>
              ))}
            </div>
            {themeForm.mode === "custom" && (
              <div className="row g-3 mb-3">
                <div className="col-6">
                  <label className="form-label fw-semibold">Primary Color</label>
                  <div className="d-flex align-items-center gap-2">
                    <input
                      type="color"
                      className="form-control form-control-color"
                      value={themeForm.primaryColor}
                      onChange={(e) => setThemeForm((f) => ({ ...f, primaryColor: e.target.value }))}
                    />
                    <code>{themeForm.primaryColor}</code>
                  </div>
                </div>
                <div className="col-6">
                  <label className="form-label fw-semibold">Accent Color</label>
                  <div className="d-flex align-items-center gap-2">
                    <input
                      type="color"
                      className="form-control form-control-color"
                      value={themeForm.accentColor}
                      onChange={(e) => setThemeForm((f) => ({ ...f, accentColor: e.target.value }))}
                    />
                    <code>{themeForm.accentColor}</code>
                  </div>
                </div>
              </div>
            )}
            <button
              className="btn btn-primary"
              onClick={handleThemeSave}
              disabled={themeSaving}
              type="button"
            >
              {themeSaving ? "Saving…" : "Save Theme"}
            </button>
          </div>
        </div>

        {/* Profile Edit */}
        <div className="card shadow-sm mb-4">
          <div className="card-header bg-primary text-white fw-semibold">Profile</div>
          <div className="card-body">
            <form onSubmit={handleProfileSave}>
              <div className="mb-3">
                <label className="form-label fw-semibold">Display Name</label>
                <input
                  className="form-control"
                  value={profile.display_name}
                  onChange={(e) => setProfile((p) => ({ ...p, display_name: e.target.value }))}
                  placeholder="Your display name"
                />
              </div>
              <div className="mb-3">
                <label className="form-label fw-semibold">Email</label>
                <input
                  className="form-control"
                  type="email"
                  value={profile.email}
                  onChange={(e) => setProfile((p) => ({ ...p, email: e.target.value }))}
                  placeholder="email@example.com"
                />
              </div>
              <div className="mb-3">
                <label className="form-label fw-semibold">Phone</label>
                <input
                  className="form-control"
                  value={profile.phone}
                  onChange={(e) => setProfile((p) => ({ ...p, phone: e.target.value }))}
                  placeholder="+91 9876543210"
                />
              </div>
              <button className="btn btn-primary" type="submit" disabled={saving}>
                {saving ? "Saving…" : "Save Profile"}
              </button>
            </form>
          </div>
        </div>

        {/* Change Password */}
        <div className="card shadow-sm mb-4">
          <div className="card-header bg-warning fw-semibold">Change Password</div>
          <div className="card-body">
            <form onSubmit={handlePasswordChange}>
              <div className="mb-3">
                <label className="form-label fw-semibold">Current Password</label>
                <input
                  className="form-control"
                  type="password"
                  value={pwForm.current_password}
                  onChange={(e) => setPwForm((p) => ({ ...p, current_password: e.target.value }))}
                  required
                  autoComplete="current-password"
                />
              </div>
              <div className="mb-3">
                <label className="form-label fw-semibold">New Password</label>
                <input
                  className="form-control"
                  type="password"
                  value={pwForm.new_password}
                  onChange={(e) => setPwForm((p) => ({ ...p, new_password: e.target.value }))}
                  required
                  minLength={4}
                  autoComplete="new-password"
                />
              </div>
              <div className="mb-3">
                <label className="form-label fw-semibold">Confirm New Password</label>
                <input
                  className="form-control"
                  type="password"
                  value={pwForm.confirm_password}
                  onChange={(e) => setPwForm((p) => ({ ...p, confirm_password: e.target.value }))}
                  required
                  minLength={4}
                  autoComplete="new-password"
                />
              </div>
              <button className="btn btn-warning" type="submit" disabled={pwSaving}>
                {pwSaving ? "Changing…" : "Change Password"}
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}
